# Category: oauth_security

from urllib.parse import urlparse
from flask import Flask, request, redirect, jsonify
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import secrets
import time

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///oauth.db'
db = SQLAlchemy(app)

class Client(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    client_id = db.Column(db.String(100), unique=True, nullable=False)
    client_secret = db.Column(db.String(200), nullable=False)
    redirect_uris = db.Column(db.Text, nullable=False)  # Comma separated
    name = db.Column(db.String(100), nullable=False)

class AuthorizationCode(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    code = db.Column(db.String(200), unique=True, nullable=False)
    client_id = db.Column(db.Integer, db.ForeignKey('client.id'), nullable=False)
    user_id = db.Column(db.Integer, nullable=False)
    redirect_uri = db.Column(db.String(200), nullable=False)
    expires_at = db.Column(db.Integer, nullable=False)
    scope = db.Column(db.Text)

class AccessToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    token = db.Column(db.String(200), unique=True, nullable=False)
    client_id = db.Column(db.Integer, db.ForeignKey('client.id'), nullable=False)
    user_id = db.Column(db.Integer, nullable=False)
    expires_at = db.Column(db.Integer, nullable=False)
    scope = db.Column(db.Text)

@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    scope = request.args.get('scope')
    
    client = Client.query.filter_by(client_id=client_id).first()
    if not client:
        return jsonify({'error': 'Invalid client'}), 400
    
    if not validate_redirect_uri(client, redirect_uri):
        return jsonify({'error': 'Invalid redirect_uri'}), 400
    
    if response_type != 'code':
        return jsonify({'error': 'Unsupported response_type'}), 400
    
    code = secrets.token_urlsafe(32)
    auth_code = AuthorizationCode(
        code=code,
        client_id=client.id,
        user_id=1,  # Dummy user
        redirect_uri=redirect_uri,
        expires_at=int(time.time()) + 300,  # 5 minutes
        scope=scope
    )
    db.session.add(auth_code)
    db.session.commit()
    
    return redirect(f"{redirect_uri}?code={code}")

@app.route('/token', methods=['POST'])
def token():
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    grant_type = request.form.get('grant_type')
    code = request.form.get('code')
    
    client = Client.query.filter_by(client_id=client_id).first()
    if not client or not check_password_hash(client.client_secret, client_secret):
        return jsonify({'error': 'Invalid client credentials'}), 400
    
    if grant_type == 'authorization_code':
        auth_code = AuthorizationCode.query.filter_by(code=code).first()
        if not auth_code or auth_code.expires_at < int(time.time()):
            return jsonify({'error': 'Invalid or expired code'}), 400
        
        if not validate_redirect_uri(client, auth_code.redirect_uri):
            return jsonify({'error': 'Mismatched redirect_uri'}), 400
        
        token = secrets.token_urlsafe(32)
        access_token = AccessToken(
            token=token,
            client_id=client.id,
            user_id=auth_code.user_id,
            expires_at=int(time.time()) + 3600,  # 1 hour
            scope=auth_code.scope
        )
        db.session.add(access_token)
        db.session.delete(auth_code)
        db.session.commit()
        
        return jsonify({
            'access_token': token,
            'token_type': 'Bearer',
            'expires_in': 3600
        })
    
    return jsonify({'error': 'Unsupported grant_type'}), 400

def validate_redirect_uri(client, redirect_uri):
    registered_uris = client.redirect_uris.split(',')
    for registered_uri in registered_uris:
        if redirect_uri.startswith(registered_uri.strip()):
            return True
    return False

